export const getInitialMarketData = (): Asset[] => {
  return initialAssets.map(asset => ({
    ...asset,
    highPrice: asset.price,
    lowPrice: asset.price
  }));
};

export const getUpdatedMarketData = (previousData: Asset[]): Asset[] => {
    return previousData.map(asset => {
        const openingPrice = asset.price;
        // Introduce more volatility. Max change can be +/- 15%
        const volatilityFactor = 0.15; 
        const changePercent = (Math.random() - 0.5) * 2 * volatilityFactor; 

        const closingPrice = openingPrice * (1 + changePercent);
        const newMarketCap = asset.marketCap * (1 + changePercent);
        const dailyChange = changePercent * 100;

        // Generate high and low prices
        const maxOC = Math.max(openingPrice, closingPrice);
        const minOC = Math.min(openingPrice, closingPrice);
        // Randomly extend high/low beyond open/close
        const highPrice = maxOC * (1 + Math.random() * (volatilityFactor / 2));
        const lowPrice = minOC * (1 - Math.random() * (volatilityFactor / 2));

        const lifetimeChange = ((closingPrice - (asset.price / (1 + asset.lifetimeChange/100))) / (asset.price / (1 + asset.lifetimeChange/100))) * 100;

        return {
            ...asset,
            price: closingPrice,
            marketCap: newMarketCap,
            dailyChange: dailyChange,
            openingPrice: openingPrice,
            highPrice,
            lowPrice,
            lifetimeChange: lifetimeChange
        };
    });
};

import { useState, useCallback, useEffect } from 'react';
import { WatchlistItem, DailyData, Asset, NewsAlertItem } from '../types';
import { getInitialMarketData, getUpdatedMarketData } from '../services/marketDataService';
import { getExecutiveSummary, getKeyNewsAlerts, getAssetInsights } from '../services/geminiService';

export const useTradingBot = () => {
  const [watchlist, setWatchlist] = useState<WatchlistItem[]>([]);
  const [dailyAdditions, setDailyAdditions] = useState<WatchlistItem[]>([]);
  const [marketData, setMarketData] = useState<Asset[]>(getInitialMarketData);
  const [currentDay, setCurrentDay] = useState<number>(0);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string>('');
  const [executiveSummary, setExecutiveSummary] = useState<string>('Initialize the market to generate the first day\'s summary.');
  const [keyNewsAlerts, setKeyNewsAlerts] = useState<NewsAlertItem>({ alerts: ['No news alerts yet.'], sources: [] });

  const advanceDay = useCallback(async (numAssets: number = 5) => {
    setIsLoading(true);
    setError('');

    try {
        const newDay = currentDay + 1;
        const newDate = new Date();
        newDate.setDate(newDate.getDate() + newDay);
        const dateString = newDate.toISOString().split('T')[0];

        const newMarketData = getUpdatedMarketData(marketData);
        setMarketData(newMarketData);

        const sortedByChange = [...newMarketData].sort((a, b) => b.dailyChange - a.dailyChange);
        const topGainers = sortedByChange.slice(0, numAssets);
        const topLosers = sortedByChange.slice(-numAssets).reverse();
        const newWatchlistAdditions = [...topGainers, ...topLosers];

        // AI-powered analysis
        const [summary, newsAlerts, assetInsights] = await Promise.all([
            getExecutiveSummary(topGainers, topLosers),
            getKeyNewsAlerts(),
            getAssetInsights(newMarketData)
        ]);
        setExecutiveSummary(summary);
        setKeyNewsAlerts(newsAlerts);

        let newAdditionsForDay: WatchlistItem[] = [];

        const updatedWatchlist = watchlist.map(item => {
            const assetUpdate = newMarketData.find(a => a.id === item.id);
            if (assetUpdate) {
                const entryPrice = item.dailyData[0].closingPrice;
                const totalPercentSinceWatchlist = ((assetUpdate.price - entryPrice) / entryPrice) * 100;

                const newDailyData: DailyData = {
                    date: dateString,
                    marketCap: assetUpdate.marketCap,
                    closingPrice: assetUpdate.price,
                    openingPrice: assetUpdate.openingPrice,
                    highPrice: assetUpdate.highPrice || assetUpdate.price,
                    lowPrice: assetUpdate.lowPrice || assetUpdate.price,
                    dailyPercentChange: assetUpdate.dailyChange,
                    totalPercentSinceWatchlist,
                    lifetimePercentChange: assetUpdate.lifetimeChange,
                    keyNewsInsight: assetInsights[item.symbol] || 'No specific insight available.'
                };
                return { ...item, dailyData: [...item.dailyData, newDailyData] };
            }
            return item;
        });

        newWatchlistAdditions.forEach(asset => {
            if (!updatedWatchlist.some(item => item.id === asset.id)) {
                const newItem: WatchlistItem = {
                    id: asset.id,
                    name: asset.name,
                    symbol: asset.symbol,
                    dateOfEntry: dateString,
                    dailyData: [{
                        date: dateString,
                        marketCap: asset.marketCap,
                        closingPrice: asset.price,
                        openingPrice: asset.openingPrice,
                        highPrice: asset.highPrice || asset.price,
                        lowPrice: asset.lowPrice || asset.price,
                        dailyPercentChange: asset.dailyChange,
                        totalPercentSinceWatchlist: 0,
                        lifetimePercentChange: asset.lifetimeChange,
                        keyNewsInsight: assetInsights[asset.symbol] || 'No specific insight available.'
                    }]
                };
                updatedWatchlist.push(newItem);
                newAdditionsForDay.push(newItem);
            }
        });

        const filteredWatchlist = updatedWatchlist.filter(item => {
            const daysOnList = (newDay - (item.dailyData[0] ? parseInt(item.dailyData[0].date.split('-')[2]) : 0));
            return daysOnList <= 42; // 6 weeks
        });

        setWatchlist(filteredWatchlist);
        setDailyAdditions(newAdditionsForDay);
        setCurrentDay(newDay);

    } catch (err) {
        console.error("Error advancing day:", err);
        setError(err instanceof Error ? err.message : 'An unknown error occurred while processing market data.');
    } finally {
        setIsLoading(false);
    }
  }, [currentDay, marketData, watchlist]);

  useEffect(() => {
    if (currentDay === 0) {
      advanceDay();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);


  return { watchlist, dailyAdditions, executiveSummary, keyNewsAlerts, currentDay, isLoading, error, advanceDay };
};

import React from 'react';
import { DailyData } from '../types';

interface PriceChartProps {
  data: DailyData[];
  width: number;
  height: number;
}

const formatCurrency = (value: number) => {
    if (value < 1) {
        return `$${value.toFixed(6)}`;
    }
    return `$${value.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
};

export const PriceChart: React.FC<PriceChartProps> = ({ data, width, height }) => {
    if (data.length < 2) {
        return (
            <div style={{ width, height }} className="flex items-center justify-center text-gray-500">
                Not enough data to display a candlestick chart.
            </div>
        );
    }

    const padding = { top: 20, right: 30, bottom: 30, left: 70 };
    const chartWidth = width - padding.left - padding.right;
    const chartHeight = height - padding.top - padding.bottom;

    // Calculate Y axis range based on High/Low prices
    const allHighs = data.map(d => d.highPrice);
    const allLows = data.map(d => d.lowPrice);
    const minPrice = Math.min(...allLows);
    const maxPrice = Math.max(...allHighs);

    const priceRange = maxPrice - minPrice === 0 ? 1 : (maxPrice - minPrice) * 1.1; // 10% buffer
    const adjustedMin = minPrice - (priceRange * 0.05);

    const getX = (index: number) => padding.left + (index / (data.length - 1)) * chartWidth;
    const getY = (price: number) => padding.top + chartHeight - ((price - adjustedMin) / priceRange) * chartHeight;

    const candleWidth = Math.max(2, (chartWidth / data.length) * 0.6);

    return (
        <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-auto overflow-visible" role="img" aria-label={`Candlestick price chart showing data over ${data.length} days.`}>
            {/* Grid lines */}
            <line x1={padding.left} y1={padding.top} x2={width - padding.right} y2={padding.top} stroke="#2d2d2d" strokeDasharray="2" />
            <line x1={padding.left} y1={padding.top + chartHeight / 2} x2={width - padding.right} y2={padding.top + chartHeight / 2} stroke="#2d2d2d" strokeDasharray="4" />
            <line x1={padding.left} y1={height - padding.bottom} x2={width - padding.right} y2={height - padding.bottom} stroke="#2d2d2d" />

            {/* Y-axis labels */}
            <text x={padding.left - 10} y={padding.top} dy="0.3em" textAnchor="end" fill="#a0a0a0" fontSize="10">{formatCurrency(maxPrice)}</text>
            <text x={padding.left - 10} y={padding.top + chartHeight / 2} dy="0.3em" textAnchor="end" fill="#a0a0a0" fontSize="10">{formatCurrency((maxPrice + minPrice) / 2)}</text>
            <text x={padding.left - 10} y={height - padding.bottom} dy="0.3em" textAnchor="end" fill="#a0a0a0" fontSize="10">{formatCurrency(minPrice)}</text>

            {/* X-axis labels */}
            <text x={padding.left} y={height - padding.bottom + 15} textAnchor="start" fill="#a0a0a0" fontSize="10">{data[0].date}</text>
            <text x={width - padding.right} y={height - padding.bottom + 15} textAnchor="end" fill="#a0a0a0" fontSize="10">{data[data.length-1].date}</text>

            {/* Candlesticks */}
            {data.map((d, i) => {
                const isBullish = d.closingPrice >= d.openingPrice;
                const color = isBullish ? '#22c55e' : '#ef4444';
                const x = getX(i);

                const highY = getY(d.highPrice);
                const lowY = getY(d.lowPrice);
                const openY = getY(d.openingPrice);
                const closeY = getY(d.closingPrice);

                const bodyTop = Math.min(openY, closeY);
                const bodyHeight = Math.abs(openY - closeY);

                return (
                    <g key={i} className="group">
                        <title>
                            {`${d.date}\nOpen: ${formatCurrency(d.openingPrice)}\nHigh: ${formatCurrency(d.highPrice)}\nLow: ${formatCurrency(d.lowPrice)}\nClose: ${formatCurrency(d.closingPrice)}`}
                        </title>
                        {/* Wick */}
                        <line 
                            x1={x} y1={highY} 
                            x2={x} y2={lowY} 
                            stroke={color} 
                            strokeWidth="1.5" 
                        />
                        {/* Body */}
                        <rect 
                            x={x - candleWidth / 2} 
                            y={bodyTop} 
                            width={candleWidth} 
                            height={Math.max(1, bodyHeight)} 
                            fill={color} 
                            className="transition-all duration-200 group-hover:opacity-80"
                        />
                    </g>
                );
            })}
        </svg>
    );
};

